import{_ as t,c as a,o as e,ae as o}from"./chunks/framework.Cd-3tpCq.js";const m=JSON.parse('{"title":"Étape 2.0 — Choisir son thème","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/choose-theme.md","filePath":"drupal-canvas/choose-theme.md"}'),r={name:"drupal-canvas/choose-theme.md"};function n(i,s,p,l,c,u){return e(),a("div",null,s[0]||(s[0]=[o(`<h1 id="etape-2-0-—-choisir-son-theme" tabindex="-1">Étape 2.0 — Choisir son thème <a class="header-anchor" href="#etape-2-0-—-choisir-son-theme" aria-label="Permalink to &quot;Étape 2.0 — Choisir son thème&quot;">​</a></h1><h2 id="deux-parcours-disponibles" tabindex="-1">Deux parcours disponibles <a class="header-anchor" href="#deux-parcours-disponibles" aria-label="Permalink to &quot;Deux parcours disponibles&quot;">​</a></h2><p>Cette formation propose deux parcours parallèles selon le framework CSS que vous souhaitez utiliser. Vous suivrez <strong>l&#39;un ou l&#39;autre</strong> selon votre projet et vos préférences.</p><table tabindex="0"><thead><tr><th></th><th><strong>Parcours A — Mercury</strong></th><th><strong>Parcours B — Bootstrap Forge</strong></th></tr></thead><tbody><tr><td><strong>Framework CSS</strong></td><td>Tailwind CSS (utility-first)</td><td>Bootstrap 5 (component-first)</td></tr><tr><td><strong>Philosophie</strong></td><td>Classes utilitaires dans le HTML</td><td>Composants CSS préconçus</td></tr><tr><td><strong>Idéal pour</strong></td><td>Designs sur-mesure, équipes connaissant Tailwind</td><td>Équipes connaissant Bootstrap, projets rapides</td></tr><tr><td><strong>Composants Canvas</strong></td><td>À créer entièrement en SDC</td><td>Fournis par le module Canvas Bootstrap</td></tr><tr><td><strong>Point d&#39;attention</strong></td><td>Contournement SDC/Tailwind nécessaire</td><td>Intégration directe, pas de contournement</td></tr></tbody></table><hr><h2 id="parcours-a-—-mercury-tailwind-css" tabindex="-1">Parcours A — Mercury (Tailwind CSS) <a class="header-anchor" href="#parcours-a-—-mercury-tailwind-css" aria-label="Permalink to &quot;Parcours A — Mercury (Tailwind CSS)&quot;">​</a></h2><p><strong>Mercury</strong> est le starterkit officiel pour Canvas sur Drupal Core. Il génère un thème basé sur <strong>Tailwind CSS</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>composer require drupal/canvas drupal/mercury</span></span>
<span class="line"><span>→ génération du thème custom via generate-theme</span></span>
<span class="line"><span>→ styles via classes Tailwind</span></span>
<span class="line"><span>→ composants SDC créés de zéro</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Attention</p><p>Les composants SDC Canvas ne sont actuellement <strong>pas compatibles nativement</strong> avec Tailwind. Un contournement est documenté dans l&#39;étape 2.3.</p></div><p><strong>Choisir Mercury si</strong> :</p><ul><li>✅ Vous aimez Tailwind CSS et ses classes utilitaires</li><li>✅ Vous voulez un contrôle total sur le design</li><li>✅ Vous construisez un design totalement sur-mesure</li></ul><p>→ <a href="/drupal-canvas/mercury-theme-structure.html">Commencer le Parcours A — Mercury</a></p><hr><h2 id="parcours-b-—-bootstrap-forge-canvas-bootstrap" tabindex="-1">Parcours B — Bootstrap Forge + Canvas Bootstrap <a class="header-anchor" href="#parcours-b-—-bootstrap-forge-canvas-bootstrap" aria-label="Permalink to &quot;Parcours B — Bootstrap Forge + Canvas Bootstrap&quot;">​</a></h2><p><strong>Bootstrap Forge</strong> est un thème Drupal basé sur <strong>Bootstrap 5</strong>. Le module <strong>Canvas Bootstrap</strong> étend Canvas pour fournir une intégration native avec Bootstrap : composants SDC prêts à l&#39;emploi, grille Bootstrap dans l&#39;éditeur, etc.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>composer require drupal/bootstrap_forge drupal/canvas_bootstrap</span></span>
<span class="line"><span>→ création d&#39;un sous-thème de Bootstrap Forge</span></span>
<span class="line"><span>→ styles via classes Bootstrap 5</span></span>
<span class="line"><span>→ composants SDC fournis par Canvas Bootstrap</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Avantage</p><p>Canvas Bootstrap fournit des composants SDC préconçus utilisant les classes Bootstrap (Card, Grid, Jumbotron…). Moins de code à écrire, intégration directe.</p></div><p><strong>Choisir Bootstrap Forge si</strong> :</p><ul><li>✅ Vous connaissez Bootstrap et ses conventions</li><li>✅ Vous voulez des composants prêts à l&#39;emploi</li><li>✅ Votre équipe ou client est familier avec Bootstrap</li></ul><p>→ <a href="/drupal-canvas/bootstrap-forge-structure.html">Commencer le Parcours B — Bootstrap Forge</a></p><hr><h2 id="puis-je-changer-d-avis" tabindex="-1">Puis-je changer d&#39;avis ? <a class="header-anchor" href="#puis-je-changer-d-avis" aria-label="Permalink to &quot;Puis-je changer d&#39;avis ?&quot;">​</a></h2><p>Oui. Les deux parcours convergent à partir du <strong>Module 3</strong> (création des pages, Patterns, contenus Drupal). La principale différence réside dans le Module 2 et dans la façon d&#39;écrire le CSS des composants SDC.</p><div class="info custom-block"><p class="custom-block-title">Pour la suite de la formation</p><p>Les modules 3 à 8 présentent les concepts de manière commune, avec des notes spécifiques quand Mercury et Bootstrap Forge se comportent différemment.</p></div>`,24)]))}const h=t(r,[["render",n]]);export{m as __pageData,h as default};
